import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, useNavigate, Link, useLocation } from 'react-router-dom';
import axios from 'axios';
import './App.css';

// --- THÀNH PHẦN DÙNG CHUNG: SIDEBAR ---
function Sidebar() {
    const location = useLocation();

    // Hàm kiểm tra xem link có đang được chọn không để đổi màu
    const activeClass = (path) => location.pathname === path ? "active-link" : "";

    return (
        <div className="sidebar">
            <div className="sidebar-header">MyAdmin</div>
            <ul className="sidebar-menu">
                <li className={activeClass('/dashboard')}><Link to="/dashboard">Dashboard</Link></li>
                <li className={activeClass('/employees')}><Link to="/employees">Hồ sơ nhân viên</Link></li>
                <li className={activeClass('/attendance')}><Link to="/attendance">Chấm công</Link></li>
                <li><Link to="#">Hợp đồng</Link></li>
                <li><Link to="#">Bảng lương</Link></li>
                <li><Link to="#">Tài khoản</Link></li>
            </ul>
