}

// --- THÀNH PHẦN DÙNG CHUNG: TOPBAR ---
function TopBar() {
    return (
        <div className="top-bar">
            <span className="system-title">HỆ THỐNG QUẢN LÝ NHÂN SỰ</span>
            <div className="user-info">
                <span>Chào Admin | <Link to="/" style={{ color: '#fff', textDecoration: 'none' }}>Đăng xuất</Link></span>
            </div>
        </div>
    );
}

// --- TRANG ĐĂNG NHẬP ---
function LoginPage() {
    const navigate = useNavigate();
    const [user, setUser] = useState('');
    const [pass, setPass] = useState('');

    const handleLogin = (e) => {
        e.preventDefault();
        navigate('/dashboard'); // Cho phép vào thẳng dashboard
    };

    return (
        <div className="login-page">
            <div className="login-card">
                <h2>HỆ THỐNG NHÂN SỰ</h2>
                <form onSubmit={handleLogin}>
                    <div className="input-group">
                        <label>Username</label>
                        <input type="text" value={user} onChange={(e) => setUser(e.target.value)} required />
                    </div>
                    <div className="input-group">
                        <label>Password</label>
                        <input type="password" value={pass} onChange={(e) => setPass(e.target.value)} required />
                    </div>
                    <button type="submit" className="btn-login">ĐĂNG NHẬP</button>
                </form>
            </div>
        </div>
    );
}

// --- TRANG DASHBOARD (TỔNG QUAN) ---
function DashboardPage() {
    const [stats, setStats] = useState({ employees: 0, teachers: 12, budget: "150.000.000 đ" });

    useEffect(() => {
        axios.get("http://localhost:8080/api/employees")
            .then(res => setStats(prev => ({ ...prev, employees: res.data.length })))
            .catch(err => console.error("Lỗi kết nối Backend:", err));
    }, []);

    return (
        <div className="dashboard-layout">
            <Sidebar />
            <div className="main-content">
                <TopBar />
                <div className="content-body">
                    <div className="stats-grid">
                        <div className="stat-card border-blue">
                            <p>SỐ NHÂN VIÊN</p>
                            <h4>{stats.employees}</h4>
                        </div>
                        <div className="stat-card border-green">
                            <p>SỐ GIẢNG VIÊN</p>
                            <h4>{stats.teachers}</h4>
                        </div>
                        <div className="stat-card border-yellow">
                            <p>TỔNG LƯƠNG THÁNG</p>
                            <h4>{stats.budget}</h4>
                        </div>
                    </div>
                    <div className="welcome-section">
                        <h3>Dashboard Tổng Quan</h3>
                        <p>Chào mừng bạn quay trở lại hệ thống quản trị.</p>
                    </div>
                </div>
            </div>
        </div>
    );
}

// --- TRANG HỒ SƠ NHÂN VIÊN ---
function EmployeePage() {
    const [employees, setEmployees] = useState([]);

    useEffect(() => {
        axios.get("http://localhost:8080/api/employees")
            .then(res => setEmployees(res.data))
            .catch(err => console.error(err));
    }, []);

    return (
        <div className="dashboard-layout">
            <Sidebar />
            <div className="main-content">
                <TopBar />
                <div className="content-body">
                    <div className="header-action">
                        <h3>Hồ sơ nhân viên / giảng viên</h3>
                        <button className="btn-primary">+ Thêm mới</button>
                    </div>
                    <table className="data-table">
                        <thead>
                            <tr>
                                <th>Họ Tên</th>
                                <th>Phòng ban</th>
                                <th>Chức vụ</th>
                                <th>Thao tác</th>
                            </tr>
                        </thead>
                        <tbody>
                            {employees.map(emp => (
                                <tr key={emp.id}>
                                    <td className="font-bold">{emp.fullName}</td>
                                    <td>{emp.department}</td>
                                    <td>{emp.position}</td>
                                    <td>
                                        <button className="btn-sm btn-edit">Sửa</button>
                                        <button className="btn-sm btn-delete">Xóa</button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}

// --- TRANG CHẤM CÔNG ---
function AttendancePage() {
    return (
        <div className="dashboard-layout">
            <Sidebar />
            <div className="main-content">
                <TopBar />
                <div className="content-body">
                    <h3>Chấm công theo ngày/giờ</h3>
                    <div className="card shadow-sm p-4">
                        <p>Lịch chấm công tháng {new Date().getMonth() + 1}</p>
                        <div className="alert-info">Chức năng này đang được kết nối với hệ thống máy chấm công vân tay...</div>
                    </div>
                </div>
            </div>
        </div>
    );
}

// --- CẤU HÌNH ROUTING ---
function App() {
    return (
        <Router>
            <Routes>
                <Route path="/" element={<LoginPage />} />
                <Route path="/dashboard" element={<DashboardPage />} />
                <Route path="/employees" element={<EmployeePage />} />
                <Route path="/attendance" element={<AttendancePage />} />
            </Routes>
        </Router>
    );
}

export default App;
